mapper.select:
SELECT dv.driver_id,
       d.driver_name,
       d.telephone,
       dv.vehicle_id,
       v.vehicle_number
FROM t_driver_vehicle dv
LEFT JOIN t_driver d ON d.driver_id = dv.driver_id
LEFT JOIN t_vehicle v ON v.vehicle_id = dv.vehicle_id
WHERE dv.driver_id = #{driverId}
  AND d.deleted_flag = #{deletedFlag}
  AND v.deleted_flag = #{deletedFlag}
  AND v.disabled_flag = #{disableFlag}

      and v.audit_status = #{auditStatus}

